import{_ as a,c as t,a5 as r,o as i}from"./chunks/framework.CcAzSe5T.js";const m=JSON.parse('{"title":"CF-DNA-Data","description":"","frontmatter":{"date":"2025-01-07T00:00:00.000Z","title":"CF-DNA-Data","status":"DONE","author":["AllenYGY"],"tags":["Data"]},"headers":[],"relativePath":"posts/Research/BioInfo/CF-DNA-Data.md","filePath":"posts/Research/BioInfo/CF-DNA-Data.md","lastUpdated":null}'),l={name:"posts/Research/BioInfo/CF-DNA-Data.md"};function o(n,e,s,h,p,c){return i(),t("div",null,e[0]||(e[0]=[r('<h1 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h1><p>replication time domain, 甲基化; Genome-wide DNA methylation analysis Open chromatin profiling with ATAC-seq Chromatin modifications profiling with Chip-seq; peak /active regulatory elements eQTL? Gene expression DNA repair related??? Clearance Mechanisms? repetitive regions (e.g., satellite DNA or LINE/SINE elements) GC contentGO biology process???</p><hr><h2 id="replication-time-domain-复制时间域" tabindex="-1">Replication Time Domain（复制时间域） <a class="header-anchor" href="#replication-time-domain-复制时间域" aria-label="Permalink to &quot;Replication Time Domain（复制时间域）&quot;">​</a></h2><p>复制时间域描述了基因组中不同区域在细胞周期中 DNA 复制的时间顺序。</p><ul><li><strong>早期复制域</strong>：通常包含活跃转录的基因和开放染色质区域。</li><li><strong>晚期复制域</strong>：通常与异染色质（非活跃的基因区域）相关。<br> 复制时间域的调控对基因组稳定性和表达有重要影响。</li></ul><p>Repli-seq</p><p><a href="https://www.encodeproject.org/search/?type=Experiment&amp;control_type!=*&amp;status=released&amp;perturbed=false&amp;searchTerm=RepliSeq&amp;limit=200" target="_blank" rel="noreferrer">ENCODE</a> 只有hg19</p><p><a href="https://data.4dnucleome.org/search/?biosample.biosource.organism.name=human&amp;q=Repli-seq+&amp;sort=biosample.biosource_summary&amp;status=released&amp;type=ExperimentReplise" target="_blank" rel="noreferrer">4DN</a> 不确定 hg19还是hg38</p><hr><h2 id="甲基化与全基因组-dna-甲基化分析-genome-wide-dna-methylation-analysis" tabindex="-1">甲基化与全基因组 DNA 甲基化分析（Genome-wide DNA Methylation Analysis） <a class="header-anchor" href="#甲基化与全基因组-dna-甲基化分析-genome-wide-dna-methylation-analysis" aria-label="Permalink to &quot;甲基化与全基因组 DNA 甲基化分析（Genome-wide DNA Methylation Analysis）&quot;">​</a></h2><ul><li><strong>甲基化</strong>：是指在 DNA 分子中添加甲基基团（通常在 CpG 位点）。这种表观遗传修饰能够调控基因表达。</li><li><strong>全基因组甲基化分析</strong>：通过技术（如 Bisulfite-Seq）检测整个基因组范围内的 DNA 甲基化模式，用于研究基因调控、疾病机制等。</li></ul><p><a href="https://www.ncbi.nlm.nih.gov/gds/?term=genome-wide+methylation" target="_blank" rel="noreferrer">NCBI</a></p><hr><h2 id="开放染色质分析-atac-seq" tabindex="-1">开放染色质分析（ATAC-seq） <a class="header-anchor" href="#开放染色质分析-atac-seq" aria-label="Permalink to &quot;开放染色质分析（ATAC-seq）&quot;">​</a></h2><ul><li><strong>ATAC-seq（Assay for Transposase-Accessible Chromatin with high-throughput sequencing）</strong>：是一种测定染色质可及性的方法，通过检测转座酶能插入的开放区域，确定潜在活跃的调控区域（如启动子、增强子）。</li><li><strong>应用</strong>：识别细胞中基因活跃调控区域，研究基因调控网络。</li></ul><p><img src="https://cdn.jsdelivr.net/gh/AllenYGY/ImageSpace@main/uPic/PqU9UK.png" alt="PqU9UK"></p><p><a href="https://www.encodeproject.org/search/?type=Experiment&amp;control_type!=*&amp;status=released&amp;perturbed=false&amp;searchTerm=ATAC-seq&amp;assay_title=ATAC-seq" target="_blank" rel="noreferrer">ENCODE</a></p><p><strong>GRCh38</strong><a href="https://www.encodeproject.org/experiments/ENCSR485TLP/" target="_blank" rel="noreferrer">ENCSR485TLP</a><a href="https://www.encodeproject.org/experiments/ENCSR032RGS/" target="_blank" rel="noreferrer">ENCSR032RGS</a> ...</p><p><a href="http://cistrome.org/db/#/" target="_blank" rel="noreferrer">Cistrome DB</a></p><p><img src="https://cdn.jsdelivr.net/gh/AllenYGY/ImageSpace@main/uPic/gFc3rk.png" alt="gFc3rk"></p><hr><h2 id="染色质修饰分析-chip-seq-与-peaks-和活跃调控元件" tabindex="-1">染色质修饰分析（ChIP-seq）与 Peaks 和活跃调控元件 <a class="header-anchor" href="#染色质修饰分析-chip-seq-与-peaks-和活跃调控元件" aria-label="Permalink to &quot;染色质修饰分析（ChIP-seq）与 Peaks 和活跃调控元件&quot;">​</a></h2><ul><li><strong>ChIP-seq（Chromatin Immunoprecipitation Sequencing）</strong>：用于研究特定蛋白（如转录因子或修饰酶）与染色质的相互作用。</li><li><strong>Peaks</strong>：代表 ChIP-seq 数据中检测到的蛋白质与 DNA 结合的高峰区域，通常对应活跃的调控元件（如启动子或增强子）。</li><li><strong>活跃调控元件</strong>：经常表现为开放染色质，结合活跃的转录因子，驱动基因表达。</li></ul><p><a href="https://chip-atlas.org/peak_browser" target="_blank" rel="noreferrer">chip-atlas</a></p><p><img src="https://cdn.jsdelivr.net/gh/AllenYGY/ImageSpace@main/uPic/QtHY08.png" alt="QtHY08"></p><hr><h2 id="eqtl-expression-quantitative-trait-loci" tabindex="-1">eQTL（Expression Quantitative Trait Loci） <a class="header-anchor" href="#eqtl-expression-quantitative-trait-loci" aria-label="Permalink to &quot;eQTL（Expression Quantitative Trait Loci）&quot;">​</a></h2><ul><li>eQTL 是一种基因组区域，控制基因表达水平的变异。</li><li><strong>类型</strong>： <ul><li><strong>Cis-eQTL</strong>：调控位点靠近目标基因。</li><li><strong>Trans-eQTL</strong>：调控位点远离目标基因。</li></ul></li><li><strong>应用</strong>：用于理解遗传变异如何影响基因表达，从而影响表型和疾病。</li></ul><hr><h2 id="dna-repair-related" tabindex="-1">DNA Repair Related <a class="header-anchor" href="#dna-repair-related" aria-label="Permalink to &quot;DNA Repair Related&quot;">​</a></h2><ul><li><strong>DNA 修复机制</strong>：细胞用来修复 DNA 损伤（如双链断裂、碱基错配等）的生物学过程。常见途径包括： <ul><li>碱基切除修复（BER）</li><li>核苷酸切除修复（NER）</li><li>同源重组修复（HR）</li><li>非同源末端连接（NHEJ）</li></ul></li></ul><hr><h2 id="clearance-mechanisms" tabindex="-1">Clearance Mechanisms <a class="header-anchor" href="#clearance-mechanisms" aria-label="Permalink to &quot;Clearance Mechanisms&quot;">​</a></h2><ul><li>指细胞清除不需要的分子或受损结构的过程。</li><li><strong>示例</strong>： <ul><li>自噬（Autophagy）：清除受损细胞器或蛋白质。</li><li>蛋白酶体介导的降解。</li><li>核酸酶清除受损 DNA。</li></ul></li></ul><hr><h2 id="repetitive-regions" tabindex="-1">Repetitive Regions <a class="header-anchor" href="#repetitive-regions" aria-label="Permalink to &quot;Repetitive Regions&quot;">​</a></h2><ul><li><strong>卫星 DNA（Satellite DNA）</strong>：存在于着丝粒或端粒的重复序列，通常参与染色体结构维护。</li><li><strong>LINE/SINE 元件</strong>：长散布元件（LINE）和短散布元件（SINE）是转座因子的一部分，可能影响基因组的稳定性。</li></ul><hr><h2 id="gc-含量-gc-content" tabindex="-1">GC 含量（GC Content） <a class="header-anchor" href="#gc-含量-gc-content" aria-label="Permalink to &quot;GC 含量（GC Content）&quot;">​</a></h2><ul><li>基因组序列中鸟嘌呤（G）和胞嘧啶（C）碱基的比例。</li><li><strong>意义</strong>： <ul><li>高 GC 含量区域通常与基因密集区相关。</li><li>影响 DNA 复制、转录和结构稳定性。</li></ul></li></ul><hr><h2 id="gene-ontology-go-生物过程-biological-process" tabindex="-1">Gene Ontology (GO) 生物过程（Biological Process） <a class="header-anchor" href="#gene-ontology-go-生物过程-biological-process" aria-label="Permalink to &quot;Gene Ontology (GO) 生物过程（Biological Process）&quot;">​</a></h2><ul><li><strong>Gene Ontology (GO)</strong>：一个标准化术语集，用于描述基因的功能。</li><li><strong>Biological Process</strong>：描述基因在生物学过程中的作用，例如信号传导、细胞分裂或代谢。</li></ul>',44)]))}const d=a(l,[["render",o]]);export{m as __pageData,d as default};
